        if (launchIntent == null) {
            Toast.makeText(
                this,
                "Automatische herstart mislukt. Sluit VT5 af en start opnieuw.",
                Toast.LENGTH_LONG,
            ).show()
            finishAffinity()
            return
        }

        val restartIntent = Intent.makeRestartActivityTask(launchIntent.component)
