        var savedPrettyPath: String? = null
        if (prettyJson != null) {
            savedPrettyPath = backupManager.writePrettyEnvelopeToSaf(
                onlineIdForFilename, 
                prettyJson
            ) ?: backupManager.writePrettyEnvelopeInternal(
                onlineIdForFilename, 
                prettyJson
            )
        }

        // 4. Upload to server via centrale uploadkern
        val uploadResult = uploadCore.uploadPrepared(
            TellingUploadCore.UploadRequest(
                mode = TellingUploadCore.Mode.FINALIZE,
                preparedEnvelope = finalEnv,
                persistReturnedOnlineId = true,
                persistPreparedEnvelopeToPrefs = true,
                markTellingSent = true
            )
        )
        val resp = uploadResult.responseText

        // 5. Write audit file
        val auditPath = try {
            backupManager.writeEnvelopeResponseToSaf(
                finalEnv.tellingid, 
                prettyJson ?: "{}", 
                resp
            ) ?: backupManager.writeEnvelopeResponseInternal(
                finalEnv.tellingid, 
                prettyJson ?: "{}", 
                resp
            )
        } catch (e: Exception) {
            Log.w(TAG, "Failed to write audit: ${e.message}", e)
            null
        }

        // 6. Handle result
        if (!uploadResult.success) {
            return@withContext AfrondResult.Failure(
                title = "Upload mislukt",
                message = "Kon telling niet uploaden:\n${uploadResult.errorMessage ?: resp}\n\n" +
                         "Envelope opgeslagen: ${savedPrettyPath ?: "niet beschikbaar"}\n" +
                         "Auditbestand: ${auditPath ?: "niet beschikbaar"}",
                savedPrettyPath = savedPrettyPath,
                auditPath = auditPath
            )
        }
        val effectiveOnlineId = uploadResult.effectiveOnlineId ?: savedOnlineId ?: finalEnv.onlineid

        // 7. Cleanup: remove backups and clear preferences
        try {
            pendingBackupDocs.forEach { doc -> 
                try { doc.delete() } catch (_: Exception) {} 
            }

            pendingBackupInternalPaths.forEach { path -> 
                try { java.io.File(path).delete() } catch (_: Exception) {} 
            }

            // Remove telling-related preferences
            prefs.edit {
                remove(PREF_ONLINE_ID)
                remove(PREF_TELLING_ID)
                remove(PREF_SAVED_ENVELOPE_JSON)
            }

            // Hybride System final actions:
            try {
                val currentTellingId = finalEnv.tellingid
                val archiveOnlineId = effectiveOnlineId.ifBlank { finalEnv.onlineid }

                // Room shadow update: Update the header with final times and counts
                hybridRepository.saveHeaderToRoom(uploadResult.preparedEnvelope, status = "geupload")

                // Extra check: Zorg dat álle records ook in Room staan (Fase 4 consistentie)
                finalRecords.forEach { record ->
                    hybridRepository.saveWaarnemingToRoom(record)
                }

                // Archive the JSON to counts folder (historical reference)
                if (prettyJson != null) {
                    envelopePersistence?.saveFinalEnvelopeToCountsDir(currentTellingId, archiveOnlineId, prettyJson)
                }

            } catch (ex: Exception) {
                Log.w(TAG, "Hybride cleanup actions failed: ${ex.message}", ex)
            }
        } catch (e: Exception) {
            Log.w(TAG, "Cleanup after successful Afronden failed: ${e.message}", e)
        }

        return@withContext AfrondResult.Success(
            savedPrettyPath = savedPrettyPath,
            auditPath = auditPath
        )
    }



    /**
     * Build envelope summary for display.
     */
    fun buildEnvelopeSummary(envelope: ServerTellingEnvelope): String {
        return dataProcessor.buildEnvelopeSummary(envelope)
    }
}

package com.yvesds.vt5.core.database.dao
import androidx.room.* import com.yvesds.vt5.core.database.entities.TellingHeader import com.yvesds.vt5.core.database.entities.Waarneming import kotlinx.coroutines.flow.Flow
// lightweight projection used for chart aggregation data class SpeciesWindDatasetRow( val begintijd: String, val timezoneid: String, val windrichting: String, val windkracht: String, val aantal: Int, val aantalterug: Int, )
// Extended debug row including ids from both waarnemingen and telling_headers for troubleshooting data class SpeciesWindDebugRow( val idLocal: String, val tellingid: String, val waarnemingOnlineId: String, val headerOnlineId: String, val begintijd: String, val timezoneid: String, val windrichting: String, val windkracht: String, val aantal: Int, val aantalterug: Int, )
// Used by DatabaseBeheerScherm to retrieve aantalterug values together with header timestamp/timezone data class HeaderReturnRow( val begintijd: String, val timezoneid: String, val aantalterug: Int, )
@Dao interface TellingDao { // TellingHeader operations @Insert(onConflict = OnConflictStrategy.REPLACE) suspend fun insertHeader(header: TellingHeader)
@Insert(onConflict = OnConflictStrategy.REPLACE) suspend fun insertHeaders(headers: List<TellingHeader>)
@Query("SELECT * FROM telling_headers WHERE tellingid = :tellingId") suspend fun getHeader(tellingId: String): TellingHeader?
@Query("SELECT * FROM telling_headers ORDER BY CAST(COALESCE(NULLIF(begintijd, ''), '0') AS INTEGER) DESC, tellingid DESC") fun getAllHeadersFlow(): Flow<List<TellingHeader>>
@Query("SELECT * FROM telling_headers ORDER BY CAST(COALESCE(NULLIF(begintijd, ''), '0') AS INTEGER) DESC, tellingid DESC") suspend fun getAllHeaders(): List<TellingHeader>
@Query("DELETE FROM waarnemingen WHERE tellingid = :tellingId") suspend fun deleteWaarnemingenVoorTellingById(tellingId: String): Int
@Query("DELETE FROM telling_headers WHERE tellingid = :tellingId") suspend fun deleteHeaderVoorTellingById(tellingId: String): Int
@Update suspend fun updateHeader(header: TellingHeader)
// Waarneming operations @Insert(onConflict = OnConflictStrategy.REPLACE) suspend fun insertWaarneming(waarneming: Waarneming)
@Insert(onConflict = OnConflictStrategy.REPLACE) suspend fun insertWaarnemingen(waarnemingen: List<Waarneming>)
@Update suspend fun updateWaarneming(waarneming: Waarneming)
@Delete suspend fun deleteWaarneming(waarneming: Waarneming)
@Query("SELECT * FROM waarnemingen WHERE tellingid = :tellingId ORDER BY tijdstip DESC") fun getWaarnemingenFlow(tellingId: String): Flow<List<Waarneming>>
@Query("SELECT * FROM waarnemingen WHERE tellingid = :tellingId") suspend fun getWaarnemingenList(tellingId: String): List<Waarneming>
@Query("SELECT * FROM waarnemingen WHERE soortid = :soortId ORDER BY tijdstip DESC") suspend fun getWaarnemingenBySoort(soortId: String): List<Waarneming>
