                        daySin.toString(),
                        dayCos.toString(),
                        hourSin.toString(),
                        hourCos.toString(),
                        sampleWeight.toString(),
                        w.soortid,
                        w.aantal
                    )
                    // Ensure each field is properly escaped/quoted so no stray commas or locales break the CSV.
                    val q = fields.map { escapeCsvField(it?.toString()) }
                    writer.write(q.joinToString(","))
                    writer.newLine()
                }
            }
            // flush and close writer
            writer.flush()
            writer.close()

            // Also write a local copy to app files dir for offline training with the Python tool (stream from created SAF file)
            try {
                val localDir = java.io.File(context.filesDir, "ai_training")
                if (!localDir.exists()) localDir.mkdirs()
                val localFile = java.io.File(localDir, filename)
                // copy via SAF input stream to local file to avoid keeping whole content in memory
                context.contentResolver.openInputStream(file.uri)?.use { input ->
                    localFile.outputStream().use { out -> input.copyTo(out) }
                }
            } catch (_: Exception) {}

            return@withContext file.name ?: filename
        }
    }

    /**
     * Parse wind direction string to degrees. Accepts numeric degrees or common compass labels
     * (N, NNO, NO, ... O for East, Z for South (Dutch labels)). Returns null if unknown.
     */
    private fun parseWindDirectionToDegrees(s: String?): Double? {
        if (s == null) return null
        val t = s.trim().uppercase(Locale.getDefault())
        if (t.isEmpty()) return null
        // try numeric
        t.replace("°", "").toDoubleOrNull()?.let { return it }

        // mapping of 16-point compass used in WeatherManager
        val labels = arrayOf("N","NNO","NO","ONO","O","OZO","ZO","ZZO","Z","ZZW","ZW","WZW","W","WNW","NW","NNW")
        val idx = labels.indexOf(t)
        if (idx >= 0) return idx * 22.5

        // Accept common English abbreviations
        val eng = mapOf(
            "N" to 0.0, "NNE" to 22.5, "NE" to 45.0, "ENE" to 67.5,
            "E" to 90.0, "ESE" to 112.5, "SE" to 135.0, "SSE" to 157.5,
            "S" to 180.0, "SSW" to 202.5, "SW" to 225.0, "WSW" to 247.5,
            "W" to 270.0, "WNW" to 292.5, "NW" to 315.0, "NNW" to 337.5
        )
        eng[t]?.let { return it }

        return null
    }
}

package com.yvesds.vt5.core.database.ui

import android.graphics.Color
import com.patrykandpatrick.vico.core.cartesian.axis.Axis
import com.patrykandpatrick.vico.core.cartesian.axis.HorizontalAxis
import com.patrykandpatrick.vico.core.cartesian.axis.VerticalAxis
import com.patrykandpatrick.vico.core.cartesian.data.CartesianValueFormatter
import com.patrykandpatrick.vico.core.cartesian.data.CartesianLayerRangeProvider
import com.patrykandpatrick.vico.core.cartesian.layer.LineCartesianLayer
import com.patrykandpatrick.vico.core.common.Fill
import com.patrykandpatrick.vico.core.common.component.LineComponent
import com.patrykandpatrick.vico.core.common.component.TextComponent

/**
 * Helper object voor Vico 2.0.0-beta.3 LineCartesianLayer configuratie.
 */
object VicoLineChartHelper {

    private val axisLabel = TextComponent(
        color = Color.WHITE,
        textSizeSp = 9f,
    )

    private val axisLine = LineComponent(
        fill = Fill(Color.LTGRAY),
        thicknessDp = 1f,
    )

    private val axisTick = LineComponent(
        fill = Fill(Color.LTGRAY),
        thicknessDp = 1f,
    )

    private val axisGuideline = LineComponent(
        fill = Fill(Color.argb(120, 180, 180, 180)),
        thicknessDp = 0.6f,
    )

    private val monthLetterByWeekStart = mapOf(
        1 to "J", 5 to "F", 9 to "M", 13 to "A", 17 to "M", 21 to "J",
        25 to "J", 29 to "A", 33 to "S", 37 to "O", 41 to "N", 45 to "D", 49 to "D"
    )

    /** Bouw één of meerdere lijnlagen met standaard cubic-bezier interpolatie. */
    fun createLineLayer(vararg lineColors: Int): LineCartesianLayer {
        val lines = lineColors.map { color ->
            val fill = Fill(color)
            // ensure stroke uses the same color explicitly so Vico draws the line in the expected color
            val stroke = LineComponent(fill = Fill(color), thicknessDp = 2f)
            LineCartesianLayer.Line(fill = LineCartesianLayer.LineFill.single(fill), stroke = stroke)
        }

        return LineCartesianLayer(
            LineCartesianLayer.LineProvider.series(*lines.toTypedArray()),
            pointSpacingDp = 2f,
        )
    }

    /** Create a dedicated LineCartesianLayer for beaufort values, fixed to 0..maxBeaufort on the Y axis */
    fun createBeaufortLineLayer(maxBeaufort: Double, beaufortColor: Int, alpha: Int = 140): LineCartesianLayer {
        // Apply requested alpha to the provided color so the beaufort line can be semi-transparent
        val a = alpha.coerceIn(0, 255)
        val withAlpha = Color.argb(a, Color.red(beaufortColor), Color.green(beaufortColor), Color.blue(beaufortColor))
        val fill = Fill(withAlpha)
        val stroke = LineComponent(fill = Fill(withAlpha), thicknessDp = 2f)
        // Try to render beaufort as points: provide a point component (large dot) and minimal stroke
        val point = LineComponent(fill = Fill(withAlpha), thicknessDp = 6f)
        val line = LineCartesianLayer.Line(fill = LineCartesianLayer.LineFill.single(fill), stroke = stroke, point = point)

        // Use a fixed range provider for Y (0..maxBeaufort). X range will remain automatic.
        val rangeProvider = CartesianLayerRangeProvider.fixed(
            /* minX */ null,
            /* maxX */ null,
            /* minY */ 0.0,
            /* maxY */ maxBeaufort,
        )

        return LineCartesianLayer(
            LineCartesianLayer.LineProvider.series(line),
            rangeProvider = rangeProvider,
            verticalAxisPosition = Axis.Position.Vertical.End,
        )
    }

    /**
     * Labels enkel per maand (ongeveer om de 4 weken): week 1, 5, 9, ...
     * We tonen enkel de maandletter.
     */
    fun createMonthLabelAxis(): HorizontalAxis<Axis.Position.Horizontal.Bottom> {
        val monthFormatter = CartesianValueFormatter { _, value, _ ->
            val week = value.toInt() + 1
            monthLetterByWeekStart[week] ?: "?"
        }

        return HorizontalAxis.bottom(
            line = axisLine,
            label = axisLabel,
            valueFormatter = monthFormatter,
            tick = axisTick,
            tickLengthDp = 4f,
            guideline = axisGuideline,
            itemPlacer = HorizontalAxis.ItemPlacer.aligned(spacing = 4, offset = 0),
        )
    }

    /** Korte verticale streepjes voor elke week, zonder labels. */
    fun createWeeklyTickAxis(): HorizontalAxis<Axis.Position.Horizontal.Top> {
        return HorizontalAxis.top(
            line = axisLine,
            label = null,
            tick = axisTick,
            tickLengthDp = 4f,
            guideline = null,
            itemPlacer = HorizontalAxis.ItemPlacer.aligned(spacing = 1, offset = 0),
        )
    }

    fun createCountAxis(): VerticalAxis<Axis.Position.Vertical.Start> {
        val formatter = CartesianValueFormatter { _, value, _ ->
            // Display counts as whole numbers, no decimals
            String.format(java.util.Locale.getDefault(), "%.0f", value)
        }

        return VerticalAxis.start(
            line = axisLine,
            label = axisLabel,
            valueFormatter = formatter,
            tick = axisTick,
            tickLengthDp = 4f,
            guideline = axisGuideline,
            itemPlacer = VerticalAxis.ItemPlacer.count(count = { 6 }),
        )
    }

    fun createBeaufortAxis(): VerticalAxis<Axis.Position.Vertical.End> {
        val formatter = CartesianValueFormatter { _, value, _ ->
            // Beaufort scale: show as whole numbers (0..7)
            String.format(java.util.Locale.getDefault(), "%.0f", value)
        }

        return VerticalAxis.end(
            line = axisLine,
            label = axisLabel,
            valueFormatter = formatter,
            tick = axisTick,
            tickLengthDp = 4f,
            guideline = null,
            // Prefer more ticks for the beaufort axis so integer steps are visible
            itemPlacer = VerticalAxis.ItemPlacer.count(count = { 8 }),
        )
    }
}

